// Initial scaffold. The executor must replace this with an implementation
// that wires capturePhoto / listPhotos / deletePhoto through the Capacitor
// Camera, Filesystem, and Preferences plugins, and exposes them on
// window.gallery.
const app = document.getElementById("app");
if (app) {
  const note = document.createElement("p");
  note.textContent = "Replace me with a Capacitor photo gallery implementation.";
  app.appendChild(note);
}

import type { CapacitorConfig } from '@capacitor/cli';

const config: CapacitorConfig = {
  appId: 'com.example.photogallery',
  appName: 'Photo Gallery',
  webDir: 'dist'
};

export default config;

