export interface MediaResult {
  /**
   * The type of media result. Either `Photo` or `Video`.
   *
   * @since 8.1.0
   */
  type: MediaType;

  /**
   * The URI pointing to the media file.
   * Not available on Web. Use `webPath` instead for Web.
   *
   * @since 8.1.0
